import {normalizedArticles} from '../fixtures'
import {DELETE_ARTICLE} from '../types'

const initialState = {}

export default function (initialState = normalizedArticles, action) {
    switch (action.type) {
        case DELETE_ARTICLE:
            return initialState.filter(article => article.id !== action.payload.id)
        default:
            return initialState
    }
}
